# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # class ToolTip(object):

# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # #     def __init__(self, widget):
# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # #         self.widget = widget
# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # #         self.tipwindow = None
