# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # #                        "style", tw._w,
# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # #                        "help", "noActivates")
# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # #         except TclError:
