# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # #         label.pack(ipadx=1)

# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # #     def hidetip(self):
# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # #         tw = self.tipwindow
# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # #         self.tipwindow = None
# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # #         if tw:
# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # #             tw.destroy()

# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # def createToolTip(widget, text):
# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # #     toolTip = ToolTip(widget)
# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # #     def enter(event):
# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # #         toolTip.showtip(text)
# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # #     def leave(event):
# # # # # # # # # # # # # # # # # # # # # # # # # # # # # # # #         toolTip.hidetip()
